#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int countGoodStrings(int A, int K, char *s) {
    int n = strlen(s);
    int count = 0;
    for (int mask = 0; mask < (1 << n); mask++) {
        int hammingDistance = 0;
        char t[n + 1];
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) == 0) {
                t[i] = s[i];
            } else {
                t[i] = 'a' + (mask & (A - 1));
                hammingDistance++;
            }
        }
        t[n] = '\0';
        if (hammingDistance <= K && isGoodString(t)) {
            count++;
        }
    }
    return count % MOD;
}
int isGoodString(char *s) {
    int n = strlen(s);
    for (int i = 0; i < n - 2; i++) {
        for (int j = i + 1; j < n - 1; j++) {
            int k = 2 * j - i;
            if (k < n && s[i] == s[j] && s[j] == s[k]) {
                return 0;
            }
        }
    }
    return 1;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, K;
        scanf("%d %d", &A, &K);
        char s[51];
        scanf("%s", s);
        printf("%d\n", countGoodStrings(A, K, s));
    }
    return 0;
}

