import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int A = sc.nextInt();
            int K = sc.nextInt();
            String s = sc.next();
            System.out.println(countGoodStrings(A, K, s));
        }
    }
    public static int countGoodStrings(int A, int K, String s) {
        int n = s.length();
        int count = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            int hammingDistance = 0;
            StringBuilder t = new StringBuilder();
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) == 0) {
                    t.append(s.charAt(i));
                } else {
                    t.append((char)('a' + (mask & (A - 1))));
                    hammingDistance++;
                }
            }
            if (hammingDistance <= K && isGoodString(t.toString())) {
                count++;
            }
        }
        return count % MOD;
    }
    public static boolean isGoodString(String s) {
        int n = s.length();
        for (int i = 0; i < n - 2; i++) {
            for (int j = i + 1; j < n - 1; j++) {
                int k = 2 * j - i;
                if (k < n && s.charAt(i) == s.charAt(j) && s.charAt(j) == s.charAt(k)) {
                    return false;
                }
            }
        }
        return true;
    }
}

